+        fs::write(path, rendered.as_bytes())?;
+        info!(path = %path.display(), "Wrote composed configuration to file");
+    }
+
+    let outcome = if cli.config_only {
+        ConfigEmitOutcome::Exit
+    } else {
+        ConfigEmitOutcome::Continue
+    };
